class BaseTransformationScene(Scene):
    """
    Quickly create function transformation animations.
    """
    @property
    def axes_config(self):
        return {
            "x_range": [0, self.plot_length, 1],
            "y_range": [-3, 3, -2],
            "axis_config": {"include_tip": False},
            "x_length": self.plot_length,
        }
    @property
    def graph_config(self):
        return {
            "function": lambda x: np.sin(x),
            "color": "PURPLE",
            "x_range": [0, self.plot_length],
        }
    def __init__(
        self, plot_length=8, function_expression=lambda x: np.sin(x), **kwargs
    ):
        self.plot_length = plot_length
        self.function_expression = function_expression
        super().__init__(**kwargs)
    def setup(self):
        self.transformation_notation = MathTex(
            "{{y=}} {{a}} {{f}} {{k}} {{(x}} {{-d)}} {{+c}}"
        )
        self.transformation_notation.to_edge(RIGHT, 1.7)
        self.a_index = 2
        self.c_index = 12
        self.d_index = 10
        self.k_index = 6
        self.axes = Axes(
            **self.axes_config,
        )
        for val in self.graph_config:
            print(f"{self.graph_config[val]}")
        self.function_object = self.axes.plot(**self.graph_config)
        self.area_under_curve = self.axes.get_area(
            self.function_object,
            x_range=[0, self.plot_length],
            color=[PURPLE, PINK, BLUE],
            fill_opacity=0.5,
        )
        self.sine_graph = VGroup.add(
            self.axes, self.function_object, self.area_under_curve
        )
        self.sine_graph.to_edge(LEFT, 1)
        self.add(self.sine_graph)
        def update_area(self):
            new_area = self.axes.get_area(
                self.function_object,
                x_range=[0, self.plot_length],
                color=[PURPLE, PINK, BLUE],
                fill_opacity=0.5,
            )
            self.area_under_curve.become(new_area)
        self.add_updater(lambda dt: update_area(self))
    def construct(self):
        return super().construct()
